#!/usr/bin/env python3
# vokra Python bindings — ctypes declaration codegen.
#
# Copyright The Vokra Authors.
# SPDX-License-Identifier: Apache-2.0
#
# Parses `include/vokra.h` (itself auto-generated by cbindgen from `vokra-capi`)
# and emits `bindings/python/src/vokra/_bindings.py` containing:
#   - vokra_status_t / vokra_event_kind_t enum constants
#   - vokra_event_t ctypes.Structure
#   - VokraSession / VokraStream opaque handle types
#   - a `bind(lib)` helper that sets argtypes/restype on every exported
#     function so ctypes marshals arguments correctly (T07).
#
# The generator is intentionally minimal: it treats vokra.h as a *pinned*
# surface (cbindgen output is deterministic; the drift check runs
# `scripts/gen-c-abi.sh --check` upstream). This script's own drift is caught
# by `check-py-bindings.sh --check` (compare emitted file byte-for-byte).
#
# Zero non-stdlib deps (NFR-DS-02): only re / pathlib / argparse / sys / os /
# difflib.

from __future__ import annotations

import argparse
import difflib
import os
import re
import sys
from pathlib import Path
from typing import List, Tuple

REPO_ROOT = Path(__file__).resolve().parents[3]
HEADER = REPO_ROOT / "include" / "vokra.h"
OUT = REPO_ROOT / "bindings" / "python" / "src" / "vokra" / "_bindings.py"

# --- C -> ctypes type map (only the primitive types that appear in vokra.h) ---
# `void` is handled as restype=None; opaque struct pointers are handled below.
PRIM_TYPES = {
    "void": "None",
    "bool": "ctypes.c_bool",
    "char": "ctypes.c_char",
    "int32_t": "ctypes.c_int32",
    "uint32_t": "ctypes.c_uint32",
    "size_t": "ctypes.c_size_t",
    "float": "ctypes.c_float",
    "double": "ctypes.c_double",
}

# Opaque handles declared as `struct <name> <name>;`. Emitted as ctypes.c_void_p
# aliases (Python side never dereferences them).
OPAQUE = {"vokra_session_t", "vokra_stream_t"}


def strip_comments(src: str) -> str:
    """Remove /* ... */ and // ... comments so regexes see only code."""
    src = re.sub(r"/\*.*?\*/", "", src, flags=re.DOTALL)
    src = re.sub(r"//[^\n]*", "", src)
    return src


def parse_enum(src: str, name: str) -> List[Tuple[str, int]]:
    """Extract `name` enum variants as (identifier, value) pairs."""
    m = re.search(
        r"typedef\s+enum\s+" + re.escape(name) + r"\s*\{([^}]*)\}\s*" + re.escape(name) + r"\s*;",
        src,
        re.DOTALL,
    )
    if not m:
        raise SystemExit(f"gen-py-bindings: enum {name} not found in {HEADER}")
    body = m.group(1)
    variants: List[Tuple[str, int]] = []
    next_val = 0
    for raw in body.split(","):
        line = raw.strip()
        if not line:
            continue
        if "=" in line:
            ident, val = line.split("=", 1)
            variants.append((ident.strip(), int(val.strip(), 0)))
            next_val = variants[-1][1] + 1
        else:
            variants.append((line, next_val))
            next_val += 1
    return variants


def map_c_type(c: str) -> str:
    """Map a C type expression (possibly with pointers) to a ctypes expression."""
    c = c.strip()
    # Peel pointer levels.
    ptrs = 0
    while c.endswith("*"):
        ptrs += 1
        c = c[:-1].strip()
    # Drop `const` / `struct` / `enum` qualifiers.
    parts = [p for p in c.split() if p not in ("const", "struct", "enum")]
    base = " ".join(parts) if parts else "void"

    if base in OPAQUE:
        # Opaque handle: `T*` -> c_void_p, `T**` -> POINTER(c_void_p).
        inner = "ctypes.c_void_p"
        ptrs -= 1  # the T itself is the void* handle
        if ptrs < 0:
            raise SystemExit(f"gen-py-bindings: opaque {base} used by value")
    elif base == "vokra_event_t":
        inner = "vokra_event_t"
    elif base in ("vokra_status_t", "vokra_event_kind_t"):
        # C enums are int-sized on all our targets.
        inner = "ctypes.c_int"
    elif base in PRIM_TYPES:
        inner = PRIM_TYPES[base]
    else:
        raise SystemExit(f"gen-py-bindings: unmapped C type {base!r}")

    if base == "char" and ptrs >= 1:
        # `char*` -> c_char_p (NUL-terminated string); `char**` -> POINTER(c_char_p).
        inner = "ctypes.c_char_p"
        ptrs -= 1

    for _ in range(ptrs):
        inner = f"ctypes.POINTER({inner})"
    return inner


def parse_functions(src: str) -> List[Tuple[str, str, List[str]]]:
    """Return [(name, restype_c, [argtype_c, ...]), ...]."""
    fns: List[Tuple[str, str, List[str]]] = []
    # Match either `enum vokra_status_t name(...)` or `type name(...)` at file scope.
    # `\s*` after ret so `const char *vokra_last_error(void);` (no space between
    # `*` and the name) still matches; every real Vokra decl uses either a
    # space-separated ret (`enum X vokra_foo(...)`, `void vokra_bar(...)`) or
    # the pointer-adjacent form.
    pattern = re.compile(
        r"(?P<ret>(?:enum\s+\w+|const\s+char\s*\*|void|char\s*\*))\s*"
        r"(?P<name>vokra_\w+)\s*\((?P<args>[^)]*)\)\s*;",
        re.DOTALL,
    )
    for m in pattern.finditer(src):
        name = m.group("name")
        ret = m.group("ret").strip()
        args_raw = m.group("args").strip()
        args: List[str] = []
        if args_raw and args_raw != "void":
            for a in args_raw.split(","):
                a = a.strip()
                # Drop the parameter name (last identifier not adjacent to *).
                # Split on whitespace or `*` boundary; keep everything except the
                # trailing identifier.
                # Approach: reverse-find the last identifier and strip it.
                tok = re.match(r"(?P<type>.+?)(?P<ident>\w+)\s*$", a, re.DOTALL)
                if not tok:
                    raise SystemExit(f"gen-py-bindings: cannot parse arg {a!r}")
                args.append(tok.group("type").strip())
        fns.append((name, ret, args))
    return fns


TEMPLATE_HEADER = '''# SPDX-License-Identifier: Apache-2.0
# !!! AUTO-GENERATED by bindings/python/scripts/gen-py-bindings.py — DO NOT EDIT. !!!
# Regenerate with `python bindings/python/scripts/gen-py-bindings.py`;
# CI enforces drift via `bindings/python/scripts/check-py-bindings.sh --check`.
#
# Source of truth: include/vokra.h (itself cbindgen output from `vokra-capi`).
# This file declares ctypes argtypes/restype so the pure-Python wrapper (T08+)
# can marshal calls into the prebuilt libvokra native library without any
# non-stdlib deps (NFR-DS-02).

from __future__ import annotations

import ctypes

# --- Enum constants (vokra_status_t) ---------------------------------------
'''


def emit(header_src: str) -> str:
    src = strip_comments(header_src)
    status_variants = parse_enum(src, "vokra_status_t")
    event_kind_variants = parse_enum(src, "vokra_event_kind_t")
    fns = parse_functions(src)

    out = [TEMPLATE_HEADER]
    for ident, val in status_variants:
        out.append(f"{ident} = {val}\n")
    out.append("\n# --- Enum constants (vokra_event_kind_t) -----------------------------------\n")
    for ident, val in event_kind_variants:
        out.append(f"{ident} = {val}\n")

    out.append(
        "\n# --- Structures ------------------------------------------------------------\n"
        "class vokra_event_t(ctypes.Structure):\n"
        "    _fields_ = [\n"
        "        (\"kind\", ctypes.c_int),\n"
        "        (\"a\", ctypes.c_uint32),\n"
        "        (\"b\", ctypes.c_float),\n"
        "    ]\n"
        "\n"
        "# Opaque handle typedefs (Python treats them as c_void_p; the runtime is\n"
        "# the only entity that dereferences them).\n"
        "VokraSession = ctypes.c_void_p\n"
        "VokraStream = ctypes.c_void_p\n"
    )

    out.append(
        "\n# --- ctypes prototypes -----------------------------------------------------\n"
        "# Populated by `bind(lib)` at import time from the loaded CDLL.\n"
        "\n"
        "PROTOTYPES = {\n"
    )
    for name, ret, args in fns:
        ret_py = map_c_type(ret)
        arg_py = ", ".join(map_c_type(a) for a in args) if args else ""
        out.append(f"    {name!r}: (\n")
        out.append(f"        {ret_py},\n")
        out.append(f"        ({arg_py},),\n" if arg_py else "        (),\n")
        out.append("    ),\n")
    out.append("}\n")

    out.append(
        "\n\n"
        "def bind(lib: ctypes.CDLL) -> ctypes.CDLL:\n"
        "    \"\"\"Attach argtypes/restype to every exported vokra_* function on `lib`.\n"
        "\n"
        "    Safe to call multiple times (idempotent). Raises AttributeError if the\n"
        "    loaded library is missing a symbol the header declares — this signals a\n"
        "    binding/library version skew and MUST fail loudly (FR-EX-08: no silent\n"
        "    fallback).\n"
        "    \"\"\"\n"
        "    for name, (restype, argtypes) in PROTOTYPES.items():\n"
        "        fn = getattr(lib, name)\n"
        "        fn.restype = restype\n"
        "        fn.argtypes = list(argtypes)\n"
        "    return lib\n"
    )
    return "".join(out)


def main() -> int:
    ap = argparse.ArgumentParser(description="Generate Vokra Python ctypes bindings.")
    ap.add_argument(
        "--check",
        action="store_true",
        help="Fail (exit 1) if the on-disk _bindings.py differs from the generator output.",
    )
    ap.add_argument(
        "--header",
        default=str(HEADER),
        help=f"Path to vokra.h (default: {HEADER}).",
    )
    ap.add_argument(
        "--out",
        default=str(OUT),
        help=f"Path to emitted _bindings.py (default: {OUT}).",
    )
    args = ap.parse_args()

    header_path = Path(args.header)
    out_path = Path(args.out)

    if not header_path.exists():
        print(f"gen-py-bindings: header not found: {header_path}", file=sys.stderr)
        return 2
    generated = emit(header_path.read_text(encoding="utf-8"))

    if args.check:
        if not out_path.exists():
            print(
                f"gen-py-bindings --check: {out_path} does not exist; run without --check to create it.",
                file=sys.stderr,
            )
            return 1
        current = out_path.read_text(encoding="utf-8")
        if current != generated:
            print(f"gen-py-bindings --check: DRIFT — {out_path} is stale.", file=sys.stderr)
            diff = difflib.unified_diff(
                current.splitlines(keepends=True),
                generated.splitlines(keepends=True),
                fromfile=str(out_path),
                tofile="<generated>",
            )
            sys.stderr.writelines(diff)
            return 1
        return 0

    out_path.parent.mkdir(parents=True, exist_ok=True)
    out_path.write_text(generated, encoding="utf-8")
    print(f"gen-py-bindings: wrote {out_path} ({len(generated)} bytes)")
    return 0


if __name__ == "__main__":
    sys.exit(main())
